package store

import "errors"

var ErrNotFound = errors.New("store: not found")

package store

import (
	"os"
	"strings"
	"sync"

	"github.com/redis/go-redis/v9"
	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"
)

const (
	redisStoreType  string = "redis"
	valkeyStoreType string = "valkey"
)

var (
	initStoreOnce = &sync.Once{}
	provider      Store
)

func Storage() Store {
	initStoreOnce.Do(func() {
		if err := initStore(); err != nil {
			klog.Fatalf("init store failed: %v", err)
		}
	})
	return provider
}

func initStore() error {
	storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
	if storeType == "" {
		storeType = redisStoreType
	}

	switch storeType {
	case redisStoreType:
		redisAddr := os.Getenv("REDIS_ADDR")
		if redisAddr == "" {
			return &initError{"REDIS_ADDR is required"}
		}

		redisPassword := os.Getenv("REDIS_PASSWORD")
		passwordRequired := strings.ToLower(os.Getenv("REDIS_PASSWORD_REQUIRED")) != "false"
		if passwordRequired && redisPassword == "" {
			return &initError{"REDIS_PASSWORD is required"}
		}

		opts := &redis.Options{
			Addr:     redisAddr,
			Password: redisPassword,
		}
		provider = newRedisStore(redis.NewClient(opts))
		return nil

	case valkeyStoreType:
		valkeyAddr := os.Getenv("VALKEY_ADDR")
		if valkeyAddr == "" {
			return &initError{"VALKEY_ADDR is required"}
		}

		valkeyPassword := os.Getenv("VALKEY_PASSWORD")
		passwordRequired := strings.ToLower(os.Getenv("VALKEY_PASSWORD_REQUIRED")) != "false"
		if passwordRequired && valkeyPassword == "" {
			return &initError{"VALKEY_PASSWORD is required"}
		}

		initAddresses := strings.Split(valkeyAddr, ",")
		clientOpts := &valkey.ClientOption{
			InitAddress:       initAddresses,
			Password:          valkeyPassword,
			DisableCache:      parseBoolEnv("VALKEY_DISABLE_CACHE"),
			ForceSingleClient: parseBoolEnv("VALKEY_FORCE_SINGLE"),
		}
		provider = newValkeyStore(valkey.NewClient(clientOpts))
		return nil

	default:
		return &initError{"unsupported store type: " + storeType}
	}
}

type initError struct {
	msg string
}

func (e *initError) Error() string {
	return e.msg
}

func parseBoolEnv(key string) bool {
	return strings.ToLower(os.Getenv(key)) == "true"
}

