	"github.com/volcano-sh/agentcube/pkg/agentd"
	utilruntime "k8s.io/apimachinery/pkg/util/runtime"
	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime"
)

func main() {
	agentd.Init()
}

func Init() {
	var (
		metricsAddr          string
		healthProbeAddr      string
		enableLeaderElection bool
	)

	flag.StringVar(&metricsAddr, "metrics-addr", ":8080", "The address the metric endpoint binds to")
	flag.StringVar(&healthProbeAddr, "health-probe-addr", ":8081", "The address the health probe endpoint binds to")
	flag.BoolVar(&enableLeaderElection, "enable-leader-election", false, "Enable leader election")

	klog.InitFlags(nil)
	flag.Parse()
}

package main

import (
	"flag"
	"fmt"
	"os"

	"github.com/volcano-sh/agentcube/pkg/picod"
	"k8s.io/klog/v2"
)

func main() {
	port := flag.Int("port", 8080, "Port for the PicoD server to listen on")
	workspace := flag.String("workspace", "", "Root directory for file operations (default: current working directory)")

	klog.InitFlags(nil)
	flag.Parse()

	config := &picod.Config{
		Port:      *port,
		Workspace: *workspace,
	}

	server, err := picod.NewServer(config)
	if err != nil {
		klog.Fatalf("failed to create server: %v", err)
	}

	klog.Infof("starting PicoD server on port %d", *port)
	if err := server.Run(); err != nil {
		fmt.Fprintf(os.Stderr, "server error: %v\n", err)
		os.Exit(1)
	}
}

